import { type Draft, produce } from 'immer';
import { type ControlProps, useControl } from './use-control';
import { useStableCallback } from './use-stable-callback';

type ImmerSetStateAction<S> = S | ((prevState: Draft<S>) => void);

/** A `useControl` variant that accepts Immer recipe updaters. */
export function useImmerControl<T, TCtx = void>(props: ControlProps<T, TCtx>) {
  const [value, setValue] = useControl<T, TCtx>(props);
  const handleChange = useStableCallback((val: ImmerSetStateAction<T>, ctx?: TCtx) =>
    setValue(current => (typeof val === 'function' ? produce(current, val as any) : val), ctx)
  );
  return [value, handleChange] as const;
}
